function EmptyState({icon,title,subtitle}){return <div style={{textAlign:"center",padding:"80px 0",color:C.grayText}}><div style={{fontSize:48,marginBottom:16}}>{icon}</div><p style={{fontSize:16,fontWeight:500,color:C.grayDark}}>{title}</p>{subtitle&&<p style={{fontSize:13,marginTop:6}}>{subtitle}</p>}</div>;}
function VolumeBar({volume,max,color}){const pct=Math.round((volume/max)*100);const col=color||(pct>66?C.orange:pct>33?C.navyMid:C.grayText);return <div style={{display:"flex",alignItems:"center",gap:8}}><div style={{width:80,height:8,background:C.grayMid,borderRadius:4,overflow:"hidden"}}><div style={{width:`${pct}%`,height:"100%",background:col,borderRadius:4}}/></div><span style={{fontSize:13,color:C.grayText,minWidth:48}}>{volume>=1000?(volume/1000).toFixed(1)+"K":volume}</span></div>;}
function PositionBadge({pos}){const color=pos<=3?C.orange:pos<=10?C.navy:pos<=20?C.navyMid:C.grayText;const bg=pos<=3?C.orangeLight:pos<=10?"#EEF1F8":pos<=20?"#F0F2F8":C.gray;return <span style={{fontWeight:700,fontSize:15,color,background:bg,padding:"4px 10px",borderRadius:8,minWidth:36,textAlign:"center",display:"inline-block"}}>#{pos}</span>;}
function MiniTrend({data}){const[tooltip,setTooltip]=useState(null);const W=80,H=32,max=Math.max(...data),min=Math.min(...data);const pts=data.map((v,i)=>({x:(i/(data.length-1))*W,y:H-((v-min)/(max-min||1))*H,v,i}));const poly=pts.map(p=>`${p.x},${p.y}`).join(" ");return <div style={{position:"relative",display:"inline-block"}}><svg width={W} height={H} onMouseLeave={()=>setTooltip(null)} onMouseMove={e=>{const r=e.currentTarget.getBoundingClientRect();const mx=e.clientX-r.left;setTooltip(pts.reduce((a,b)=>Math.abs(b.x-mx)<Math.abs(a.x-mx)?b:a));}}><polyline points={poly} fill="none" stroke={C.orange} strokeWidth="2" strokeLinejoin="round"/>{tooltip&&<><line x1={tooltip.x} y1={0} x2={tooltip.x} y2={H} stroke={C.orange} strokeWidth="1" strokeDasharray="3,2"/><circle cx={tooltip.x} cy={tooltip.y} r={3} fill={C.orange}/></>}</svg>{tooltip&&<div style={{position:"absolute",bottom:"calc(100% + 6px)",left:tooltip.x>50?"auto":tooltip.x-28,right:tooltip.x>50?0:"auto",background:C.navy,color:C.white,fontSize:11,padding:"4px 8px",borderRadius:6,whiteSpace:"nowrap",pointerEvents:"none",zIndex:10}}>{MONTHS[tooltip.i]}: {tooltip.v>=1000?(tooltip.v/1000).toFixed(1)+"K":tooltip.v}</div>}</div>;}
function PositionChart({history}){const[tip,setTip]=useState(null);const[range,setRange]=useState("14");if(!history||history.length===0)return null;const filtered=range==="all"?history:history.slice(-parseInt(range));const W=200,H=50,pad=4;const positions=filtered.map(e=>e.position);const maxP=Math.max(...positions),minP=Math.min(...positions);const pts=filtered.map((e,i)=>({x:pad+(i/Math.max(filtered.length-1,1))*(W-pad*2),y:pad+((e.position-minP)/((maxP-minP)||1))*(H-pad*2),pos:e.position,date:e.date}));const poly=pts.map(p=>`${p.x},${p.y}`).join(" ");return <div style={{display:"flex",flexDirection:"column",gap:4}}><div style={{display:"flex",gap:4}}>{[["7","7z"],["14","14z"],["30","30z"],["all","Tot"]].map(([val,label])=><button key={val} onClick={()=>setRange(val)} style={{padding:"2px 7px",fontSize:10,borderRadius:5,border:"1.5px solid",cursor:"pointer",fontWeight:500,borderColor:range===val?C.orange:C.border,background:range===val?C.orangeLight:C.white,color:range===val?C.orange:C.grayText}}>{label}</button>)}</div><div style={{position:"relative",display:"inline-block"}}><svg width={W} height={H} onMouseLeave={()=>setTip(null)} onMouseMove={e=>{const r=e.currentTarget.getBoundingClientRect();const mx=e.clientX-r.left;setTip(pts.reduce((a,b)=>Math.abs(b.x-mx)<Math.abs(a.x-mx)?b:a));}}><polyline points={poly} fill="none" stroke={C.navy} strokeWidth="2" strokeLinejoin="round"/>{tip&&<><line x1={tip.x} y1={0} x2={tip.x} y2={H} stroke={C.navy} strokeWidth="1" strokeDasharray="3,2"/><circle cx={tip.x} cy={tip.y} r={3} fill={C.navy}/></>}</svg>{tip&&<div style={{position:"absolute",bottom:"calc(100% + 4px)",left:tip.x>140?"auto":tip.x-20,right:tip.x>140?0:"auto",background:C.navy,color:C.white,fontSize:11,padding:"4px 8px",borderRadius:6,whiteSpace:"nowrap",pointerEvents:"none",zIndex:10}}>{tip.date}: #{tip.pos}</div>}</div></div>;}
function exportCSV(data,query){const blob=new Blob(["Keyword,Volum lunar\n"+data.map(r=>`"${r.keyword}",${r.volume}`).join("\n")],{type:"text/csv;charset=utf-8;"});const url=URL.createObjectURL(blob);const a=document.createElement("a");a.href=url;a.download=`keywords_${query.replace(/\s+/g,"_")}.csv`;a.click();URL.revokeObjectURL(url);}

function CalendarPicker({label,value,onChange,minDate,maxDate}){const[open,setOpen]=useState(false);const[view,setView]=useState(()=>value?new Date(value+"T00:00:00"):new Date());const year=view.getFullYear(),month=view.getMonth();const firstDay=new Date(year,month,1).getDay();const daysInMonth=new Date(year,month+1,0).getDate();const DAYS=["Lu","Ma","Mi","Jo","Vi","Sâ","Du"];const MONS=["Ian","Feb","Mar","Apr","Mai","Iun","Iul","Aug","Sep","Oct","Nov","Dec"];const cells=[];const startOffset=(firstDay+6)%7;for(let i=0;i<startOffset;i++)cells.push(null);for(let d=1;d<=daysInMonth;d++)cells.push(new Date(year,month,d));const selDate=value?new Date(value+"T00:00:00"):null;const isDisabled=d=>{if(!d)return true;if(minDate&&d<new Date(minDate+"T00:00:00"))return true;if(maxDate&&d>new Date(maxDate+"T00:00:00"))return true;return false;};return <div style={{position:"relative",display:"inline-block"}}><div onClick={()=>setOpen(o=>!o)} style={{display:"flex",alignItems:"center",gap:8,padding:"8px 12px",border:`1.5px solid ${open?C.orange:C.border}`,borderRadius:8,cursor:"pointer",background:C.white,fontSize:13,color:value?C.navy:C.grayText,minWidth:130,userSelect:"none"}}><span>📅</span><span>{value||label}</span></div>{open&&<div style={{position:"absolute",top:"calc(100% + 6px)",left:0,zIndex:200,background:C.white,border:`1.5px solid ${C.border}`,borderRadius:12,boxShadow:"0 8px 30px rgba(0,0,0,0.12)",padding:14,width:240}}><div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10}}><button onClick={()=>setView(new Date(year,month-1,1))} style={{background:"none",border:"none",cursor:"pointer",fontSize:16,color:C.navy,padding:"2px 6px"}}>‹</button><span style={{fontWeight:600,fontSize:13,color:C.navy}}>{MONS[month]} {year}</span><button onClick={()=>setView(new Date(year,month+1,1))} style={{background:"none",border:"none",cursor:"pointer",fontSize:16,color:C.navy,padding:"2px 6px"}}>›</button></div><div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:2,marginBottom:4}}>{DAYS.map(d=><div key={d} style={{textAlign:"center",fontSize:10,fontWeight:600,color:C.grayText,padding:"2px 0"}}>{d}</div>)}</div><div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:2}}>{cells.map((d,i)=>{if(!d)return <div key={i}/>;const sel=selDate&&d.toDateString()===selDate.toDateString();const dis=isDisabled(d);return <div key={i} onClick={()=>{if(!dis){onChange(fmtDate(d));setOpen(false);}}} style={{textAlign:"center",padding:"5px 2px",borderRadius:6,fontSize:12,cursor:dis?"default":"pointer",fontWeight:sel?700:400,background:sel?C.orange:"transparent",color:dis?C.grayMid:sel?C.white:C.navy,opacity:dis?0.4:1}} onMouseEnter={e=>{if(!dis&&!sel)e.currentTarget.style.background=C.orangeLight;}} onMouseLeave={e=>{if(!sel)e.currentTarget.style.background="transparent";}}>{d.getDate()}</div>;})}</div></div>}</div>;}

function ProjectChart({keywords}){const today=new Date();const[device,setDevice]=useState("all");const[mode,setMode]=useState("preset");const[preset,setPreset]=useState("14");const[p1Start,setP1Start]=useState(fmtDate(addDays(today,-13)));const[p1End,setP1End]=useState(fmtDate(today));const[p2Start,setP2Start]=useState(fmtDate(addDays(today,-27)));const[p2End,setP2End]=useState(fmtDate(addDays(today,-14)));const[tip,setTip]=useState(null);if(!keywords||keywords.length===0)return null;const kws=device==="all"?keywords:keywords.filter(k=>k.device===device);const allDates=[...new Set(kws.flatMap(k=>(k.history||[]).map(h=>h.date)))].map(d=>({str:d,ts:parseHistoryDate(d)})).filter(d=>d.ts).sort((a,b)=>a.ts-b.ts);const avgForDates=dates=>dates.map(({str,ts})=>{const pos=kws.map(k=>{const h=(k.history||[]).find(e=>e.date===str);return h?h.position:null;}).filter(Boolean);return{str,ts,avg:pos.length?Math.round(pos.reduce((a,b)=>a+b,0)/pos.length):null};}).filter(e=>e.avg!==null);let series1=[],series2=[],compareMode=false;if(mode==="preset"){const n=preset==="all"?allDates.length:parseInt(preset);series1=avgForDates(allDates.slice(-n));}else if(mode==="custom"){const s=new Date(p1Start+"T00:00:00"),e=new Date(p1End+"T23:59:59");series1=avgForDates(allDates.filter(d=>d.ts>=s&&d.ts<=e));}else if(mode==="compare"){compareMode=true;const s1=new Date(p1Start+"T00:00:00"),e1=new Date(p1End+"T23:59:59"),s2=new Date(p2Start+"T00:00:00"),e2=new Date(p2End+"T23:59:59");series1=avgForDates(allDates.filter(d=>d.ts>=s1&&d.ts<=e1));series2=avgForDates(allDates.filter(d=>d.ts>=s2&&d.ts<=e2));}const curPos=kws.map(k=>k.position);const curAvg=curPos.length?Math.round(curPos.reduce((a,b)=>a+b,0)/curPos.length):0;const curTop3=curPos.filter(p=>p<=3).length,curTop10=curPos.filter(p=>p<=10).length;const svgW=560,H=140,pad={t:12,r:16,b:28,l:36};const allForScale=compareMode?[...series1,...series2]:series1;const allAvgs=allForScale.map(e=>e.avg);const scaleMax=Math.max(...allAvgs,1),scaleMin=Math.min(...allAvgs,1);const toPt=series=>series.map((e,i)=>({x:pad.l+(i/Math.max(series.length-1,1))*(svgW-pad.l-pad.r),y:pad.t+((e.avg-scaleMin)/((scaleMax-scaleMin)||1))*(H-pad.t-pad.b),avg:e.avg,str:e.str}));const pts1=toPt(series1),pts2=compareMode?toPt(series2):[];const toLine=pts=>pts.map(p=>`${p.x},${p.y}`).join(" ");const yTicks=[scaleMin,Math.round((scaleMin+scaleMax)/2),scaleMax].filter((v,i,a)=>a.indexOf(v)===i);const avg1=series1.length?Math.round(series1.reduce((s,e)=>s+e.avg,0)/series1.length):null;const avg2=series2.length?Math.round(series2.reduce((s,e)=>s+e.avg,0)/series2.length):null;const diff=avg1!==null&&avg2!==null?avg2-avg1:null;
return(<div style={{background:C.white,borderRadius:12,border:`1px solid ${C.border}`,padding:20,marginBottom:20}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:16,flexWrap:"wrap",gap:10}}><div><div style={{fontWeight:600,fontSize:15,marginBottom:2}}>Raportare pozitii</div><div style={{fontSize:12,color:C.grayText}}>{kws.length} keywords {device!=="all"?`· ${device}`:""}</div></div><div style={{display:"flex",gap:4}}>{[["all","Toate"],["desktop","Desktop"],["mobile","Mobil"]].map(([val,label])=><button key={val} onClick={()=>setDevice(val)} style={{padding:"5px 12px",fontSize:12,borderRadius:7,border:"1.5px solid",cursor:"pointer",fontWeight:500,borderColor:device===val?C.orange:C.border,background:device===val?C.orangeLight:C.white,color:device===val?C.orange:C.grayText}}>{label}</button>)}</div></div><div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10,marginBottom:18}}>{[{label:"Pozitie medie curenta",value:curPos.length?`#${curAvg}`:"—",color:C.navy,bg:"#EEF1F8"},{label:"Keywords Top 3",value:curTop3,color:C.orange,bg:C.orangeLight},{label:"Keywords Top 10",value:curTop10,color:C.navy,bg:"#EEF1F8"}].map((s,i)=><div key={i} style={{background:s.bg,borderRadius:8,padding:"10px 14px"}}><div style={{fontSize:11,color:C.grayText,marginBottom:3}}>{s.label}</div><div style={{fontSize:22,fontWeight:700,color:s.color}}>{s.value}</div></div>)}</div><div style={{display:"flex",gap:6,marginBottom:14}}>{[["preset","Preset"],["custom","Perioadă custom"],["compare","Compară perioade"]].map(([val,label])=><button key={val} onClick={()=>setMode(val)} style={{padding:"6px 14px",borderRadius:8,border:"1.5px solid",fontSize:12,cursor:"pointer",fontWeight:500,borderColor:mode===val?C.orange:C.border,background:mode===val?C.orangeLight:C.white,color:mode===val?C.orange:C.grayText}}>{label}</button>)}</div>{mode==="preset"&&<div style={{display:"flex",gap:6,marginBottom:14}}>{[["7","7 zile"],["14","14 zile"],["30","30 zile"],["all","Tot"]].map(([val,label])=><button key={val} onClick={()=>setPreset(val)} style={{padding:"5px 12px",fontSize:12,borderRadius:7,border:"1.5px solid",cursor:"pointer",fontWeight:500,borderColor:preset===val?C.navy:C.border,background:preset===val?"#EEF1F8":C.white,color:preset===val?C.navy:C.grayText}}>{label}</button>)}</div>}{mode==="custom"&&<div style={{display:"flex",alignItems:"center",gap:10,marginBottom:14,flexWrap:"wrap"}}><span style={{fontSize:12,color:C.grayText,fontWeight:500}}>De la</span><CalendarPicker label="Data start" value={p1Start} onChange={setP1Start} maxDate={p1End}/><span style={{fontSize:12,color:C.grayText,fontWeight:500}}>până la</span><CalendarPicker label="Data end" value={p1End} onChange={setP1End} minDate={p1Start} maxDate={fmtDate(today)}/></div>}{mode==="compare"&&<div style={{display:"flex",gap:16,marginBottom:14,flexWrap:"wrap"}}><div style={{display:"flex",alignItems:"center",gap:8,background:"#EEF1F8",padding:"8px 12px",borderRadius:10}}><div style={{width:10,height:10,borderRadius:"50%",background:C.navy,flexShrink:0}}/><span style={{fontSize:12,fontWeight:500,color:C.navy,marginRight:4}}>P1</span><CalendarPicker label="Start" value={p1Start} onChange={setP1Start} maxDate={p1End}/><span style={{fontSize:11,color:C.grayText}}>→</span><CalendarPicker label="End" value={p1End} onChange={setP1End} minDate={p1Start} maxDate={fmtDate(today)}/></div><div style={{display:"flex",alignItems:"center",gap:8,background:C.orangeLight,padding:"8px 12px",borderRadius:10}}><div style={{width:10,height:10,borderRadius:"50%",background:C.orange,flexShrink:0}}/><span style={{fontSize:12,fontWeight:500,color:C.orange,marginRight:4}}>P2</span><CalendarPicker label="Start" value={p2Start} onChange={setP2Start} maxDate={p2End}/><span style={{fontSize:11,color:C.grayText}}>→</span><CalendarPicker label="End" value={p2End} onChange={setP2End} minDate={p2Start} maxDate={fmtDate(today)}/></div></div>}{compareMode&&avg1!==null&&avg2!==null&&<div style={{display:"flex",gap:10,marginBottom:14,alignItems:"center",flexWrap:"wrap"}}><div style={{background:"#EEF1F8",borderRadius:8,padding:"8px 16px",fontSize:13}}><span style={{color:C.grayText}}>P1 medie: </span><strong style={{color:C.navy}}>#{avg1}</strong></div><div style={{background:C.orangeLight,borderRadius:8,padding:"8px 16px",fontSize:13}}><span style={{color:C.grayText}}>P2 medie: </span><strong style={{color:C.orange}}>#{avg2}</strong></div><div style={{background:diff<0?"#E8F5E9":diff>0?"#FFF0F0":C.gray,borderRadius:8,padding:"8px 16px",fontSize:13}}><span style={{color:C.grayText}}>Diferenta: </span><strong style={{color:diff<0?"#2E7D32":diff>0?"#C62828":C.grayText}}>{diff===0?"—":diff<0?`▲ ${Math.abs(diff)} pozitii mai sus`:`▼ ${diff} pozitii mai jos`}</strong></div></div>}{series1.length<2?<div style={{textAlign:"center",padding:"30px 0",color:C.grayText,fontSize:13}}>Nu există suficiente date pentru perioada selectată.</div>:<div style={{position:"relative"}}><svg viewBox={`0 0 ${svgW} ${H}`} style={{width:"100%",height:H}} onMouseLeave={()=>setTip(null)} onMouseMove={e=>{const r=e.currentTarget.getBoundingClientRect();const mx=(e.clientX-r.left)/r.width*svgW;const near1=pts1.length?pts1.reduce((a,b)=>Math.abs(b.x-mx)<Math.abs(a.x-mx)?b:a):null;const near2=pts2.length?pts2.reduce((a,b)=>Math.abs(b.x-mx)<Math.abs(a.x-mx)?b:a):null;setTip({x:near1?near1.x:near2?.x,p1:near1,p2:near2});}}>{yTicks.map((v,i)=>{const yy=pad.t+((v-scaleMin)/((scaleMax-scaleMin)||1))*(H-pad.t-pad.b);return<g key={i}><line x1={pad.l} y1={yy} x2={svgW-pad.r} y2={yy} stroke={C.grayMid} strokeWidth="1" strokeDasharray="4,3"/><text x={pad.l-4} y={yy+4} fontSize="9" fill={C.grayText} textAnchor="end">#{v}</text></g>})}{pts1.filter((_,i)=>i%Math.max(1,Math.floor(pts1.length/6))===0).map((p,i)=><text key={i} x={p.x} y={H-4} fontSize="9" fill={C.grayText} textAnchor="middle">{p.str}</text>)}{pts1.length>1&&<polyline points={toLine(pts1)} fill="none" stroke={C.navy} strokeWidth="2.5" strokeLinejoin="round"/>}{pts2.length>1&&<polyline points={toLine(pts2)} fill="none" stroke={C.orange} strokeWidth="2.5" strokeLinejoin="round" strokeDasharray="6,3"/>}{tip&&<line x1={tip.x} y1={pad.t} x2={tip.x} y2={H-pad.b} stroke={C.grayMid} strokeWidth="1" strokeDasharray="3,2"/>}{tip?.p1&&<circle cx={tip.p1.x} cy={tip.p1.y} r={4} fill={C.navy}/>}{tip?.p2&&<circle cx={tip.p2.x} cy={tip.p2.y} r={4} fill={C.orange}/>}</svg>{tip&&(tip.p1||tip.p2)&&<div style={{position:"absolute",top:8,left:tip.x/svgW*100>65?"auto":`calc(${tip.x/svgW*100}% + 10px)`,right:tip.x/svgW*100>65?`calc(${(1-tip.x/svgW)*100}% + 10px)`:"auto",background:C.navy,color:C.white,fontSize:11,padding:"6px 10px",borderRadius:8,pointerEvents:"none",whiteSpace:"nowrap",lineHeight:1.8}}>{tip.p1&&<div><span style={{color:"#aac4ff"}}>P1 {tip.p1.str}:</span> <strong>#{tip.p1.avg}</strong></div>}{tip.p2&&<div><span style={{color:"#ffb899"}}>P2 {tip.p2.str}:</span> <strong>#{tip.p2.avg}</strong></div>}</div>}</div>}<div style={{display:"flex",gap:16,marginTop:8}}><div style={{display:"flex",alignItems:"center",gap:6,fontSize:11,color:C.grayText}}><div style={{width:20,height:2.5,background:C.navy,borderRadius:2}}/>{compareMode?"Perioada 1":"Medie pozitii"}</div>{compareMode&&<div style={{display:"flex",alignItems:"center",gap:6,fontSize:11,color:C.grayText}}><svg width="20" height="4"><line x1="0" y1="2" x2="20" y2="2" stroke={C.orange} strokeWidth="2.5" strokeDasharray="5,3"/></svg>Perioada 2</div>}</div></div>);}

// ── Projects Home ─────────────────────────────────────────────────────────────
function ProjectsHome({ projects, onSelectProject, onNewProject }) {
  const getProjectStats = p => {
    const pos = p.keywords.map(k => k.position);
    const avg = pos.length ? Math.round(pos.reduce((a,b)=>a+b,0)/pos.length) : null;
    const top3 = pos.filter(p=>p<=3).length;
    const top10 = pos.filter(p=>p<=10).length;
    return { avg, top3, top10 };
  };

  return (
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:32}}>
        <div>
          <h1 style={{fontSize:24,fontWeight:800,color:C.navy,marginBottom:6}}>Proiectele tale</h1>
          <p style={{color:C.grayText,fontSize:14}}>Selectează un proiect pentru a vedea Rank Tracker-ul.</p>
        </div>
        <button onClick={onNewProject} style={{padding:"11px 22px",background:C.orange,color:C.white,border:"none",borderRadius:10,fontWeight:700,fontSize:14,cursor:"pointer",display:"flex",alignItems:"center",gap:8}}>
          + Proiect nou
        </button>
      </div>

      {projects.length === 0 ? (
        <div style={{textAlign:"center",padding:"80px 0"}}>
          <div style={{fontSize:56,marginBottom:20}}>📂</div>
          <p style={{fontSize:18,fontWeight:600,color:C.grayDark,marginBottom:8}}>Niciun proiect încă</p>
          <p style={{fontSize:14,color:C.grayText,marginBottom:28}}>Creează primul tău proiect pentru a începe să monitorizezi poziții.</p>
          <button onClick={onNewProject} style={{padding:"12px 28px",background:C.orange,color:C.white,border:"none",borderRadius:10,fontWeight:700,fontSize:15,cursor:"pointer"}}>+ Creează primul proiect</button>
        </div>
      ) : (
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(280px,1fr))",gap:20}}>
          {projects.map(p => {
            const stats = getProjectStats(p);
            return (
              <div key={p.id} onClick={()=>onSelectProject(p.id)}
                style={{background:C.white,border:`1.5px solid ${C.border}`,borderRadius:14,padding:24,cursor:"pointer",transition:"all 0.15s"}}
                onMouseEnter={e=>{e.currentTarget.style.borderColor=C.orange;e.currentTarget.style.boxShadow="0 4px 20px rgba(255,107,43,0.12)";}}
                onMouseLeave={e=>{e.currentTarget.style.borderColor=C.border;e.currentTarget.style.boxShadow="none";}}>
                {/* header */}
                <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",marginBottom:16}}>
                  <div>
                    <div style={{fontWeight:700,fontSize:16,color:C.navy,marginBottom:4}}>{p.name}</div>
                    {p.url && <div style={{fontSize:12,color:C.orange}}>{p.url}</div>}
                  </div>
                  <div style={{width:36,height:36,background:C.orangeLight,borderRadius:9,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                    <span style={{fontSize:18}}>📈</span>
                  </div>
                </div>
                {/* stats */}
                {p.keywords.length > 0 ? (
                  <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8,marginBottom:16}}>
                    {[
                      {label:"Poz. medie",value:stats.avg?`#${stats.avg}`:"—",color:C.navy},
                      {label:"Top 3",value:stats.top3,color:C.orange},
                      {label:"Top 10",value:stats.top10,color:C.navyMid},
                    ].map((s,i)=>(
                      <div key={i} style={{background:C.gray,borderRadius:8,padding:"8px 10px",textAlign:"center"}}>
                        <div style={{fontSize:10,color:C.grayText,marginBottom:3}}>{s.label}</div>
                        <div style={{fontSize:18,fontWeight:700,color:s.color}}>{s.value}</div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div style={{background:C.gray,borderRadius:8,padding:"10px 14px",marginBottom:16,fontSize:12,color:C.grayText}}>Niciun keyword adăugat încă</div>
                )}
                <div style={{display:"flex",alignItems:"center",justifyContent:"space-between"}}>
                  <span style={{fontSize:12,color:C.grayText}}>{p.keywords.length} keyword{p.keywords.length!==1?"s":""}</span>
                  <span style={{fontSize:12,fontWeight:600,color:C.orange}}>Deschide →</span>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

// ── Login ─────────────────────────────────────────────────────────────────────
function LoginScreen({onLogin}){const[username,setUsername]=useState("");const[password,setPassword]=useState("");const[error,setError]=useState("");const[showPass,setShowPass]=useState(false);const handleLogin=()=>{const match=USERS.find(u=>u.username===username.trim()&&u.password===password);if(match){onLogin(match.username);}else{setError("User sau parolă incorectă.");}};return(<div style={{display:"flex",alignItems:"center",justifyContent:"center",height:"100vh",background:C.navy,fontFamily:"Inter,'Segoe UI',sans-serif"}}><div style={{background:C.white,borderRadius:20,padding:"40px 36px",width:360,boxShadow:"0 24px 80px rgba(0,0,0,0.25)"}}><div style={{marginBottom:32}}><Logo variant="light" width={200}/></div><div style={{marginBottom:16}}><label style={{fontSize:12,fontWeight:600,color:C.grayDark,display:"block",marginBottom:6}}>Utilizator</label><input value={username} onChange={e=>{setUsername(e.target.value);setError("");}} onKeyDown={e=>e.key==="Enter"&&handleLogin()} placeholder="Nume utilizator" autoComplete="username" style={{width:"100%",padding:"11px 14px",border:`1.5px solid ${C.border}`,borderRadius:9,fontSize:14,outline:"none",boxSizing:"border-box",color:C.navy}} onFocus={e=>e.target.style.borderColor=C.orange} onBlur={e=>e.target.style.borderColor=C.border}/></div><div style={{marginBottom:8}}><label style={{fontSize:12,fontWeight:600,color:C.grayDark,display:"block",marginBottom:6}}>Parolă</label><div style={{position:"relative"}}><input value={password} onChange={e=>{setPassword(e.target.value);setError("");}} onKeyDown={e=>e.key==="Enter"&&handleLogin()} type={showPass?"text":"password"} placeholder="••••••••" autoComplete="current-password" style={{width:"100%",padding:"11px 40px 11px 14px",border:`1.5px solid ${C.border}`,borderRadius:9,fontSize:14,outline:"none",boxSizing:"border-box",color:C.navy}} onFocus={e=>e.target.style.borderColor=C.orange} onBlur={e=>e.target.style.borderColor=C.border}/><span onClick={()=>setShowPass(v=>!v)} style={{position:"absolute",right:12,top:"50%",transform:"translateY(-50%)",cursor:"pointer",fontSize:16,userSelect:"none"}}>{showPass?"🙈":"👁️"}</span></div></div>{error&&<div style={{fontSize:12,color:C.red,marginBottom:12,padding:"8px 12px",background:C.redLight,borderRadius:7}}>⚠️ {error}</div>}<button onClick={handleLogin} style={{width:"100%",padding:"12px",background:C.orange,color:C.white,border:"none",borderRadius:9,fontWeight:700,fontSize:15,cursor:"pointer",marginTop:8}}>Intră în cont</button><div style={{textAlign:"center",marginTop:16}}><span onClick={()=>setError("Contactează administratorul AdSem pentru resetarea parolei.")} style={{fontSize:12,color:C.grayText,cursor:"pointer",textDecoration:"underline"}}>Am uitat parola</span></div></div></div>);}

// ── Keyword Research ──────────────────────────────────────────────────────────
function KeywordResearch({onAddToTracker}){const[query,setQuery]=useState("");const[results,setResults]=useState(null);const[loading,setLoading]=useState(false);const[searched,setSearched]=useState("");const[sortDir,setSortDir]=useState("desc");const[selected,setSelected]=useState(new Set());const[added,setAdded]=useState(false);const handleSearch=()=>{if(!query.trim())return;setLoading(true);setResults(null);setSelected(new Set());setTimeout(()=>{setResults(generateKeywords(query));setSearched(query);setSortDir("desc");setLoading(false);},800);};const sorted=results?[...results].sort((a,b)=>sortDir==="desc"?b.volume-a.volume:a.volume-b.volume):[];const maxVol=results?Math.max(...results.map(r=>r.volume)):1;const toggleSelect=kw=>{const s=new Set(selected);s.has(kw)?s.delete(kw):s.add(kw);setSelected(s);};const toggleAll=e=>{if(e.target.checked)setSelected(new Set(sorted.map(r=>r.keyword)));else setSelected(new Set());};const handleAddToTracker=()=>{if(selected.size===0)return;onAddToTracker([...selected]);setAdded(true);setTimeout(()=>setAdded(false),2000);};return <div><h1 style={{fontSize:22,fontWeight:700,marginBottom:4}}>Keyword Research</h1><p style={{color:C.grayText,fontSize:14,marginBottom:24}}>Descopera volume de cautare si variatii de keywords pentru Romania.</p><div style={{display:"flex",gap:10,marginBottom:28}}><div style={{flex:1,position:"relative"}}><span style={{position:"absolute",left:14,top:"50%",transform:"translateY(-50%)",color:C.grayText}}>🔍</span><input value={query} onChange={e=>setQuery(e.target.value)} onKeyDown={e=>e.key==="Enter"&&handleSearch()} placeholder="Ex: bec led, pantofi sport..." style={{width:"100%",padding:"12px 14px 12px 40px",border:`1.5px solid ${C.border}`,borderRadius:10,fontSize:15,outline:"none",background:C.white,boxSizing:"border-box"}} onFocus={e=>e.target.style.borderColor=C.orange} onBlur={e=>e.target.style.borderColor=C.border}/></div><button onClick={handleSearch} style={{padding:"12px 28px",background:C.orange,color:C.white,border:"none",borderRadius:10,fontWeight:600,fontSize:15,cursor:"pointer"}}>Cauta</button></div>{loading&&<EmptyState icon="⏳" title="Se incarca rezultatele..."/>}{results&&!loading&&<div><div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:16,flexWrap:"wrap",gap:10}}><div style={{display:"flex",alignItems:"center",gap:12}}><span style={{fontSize:14,color:C.grayText}}><strong style={{color:C.navy}}>{results.length}</strong> keyword-uri pentru <strong style={{color:C.orange}}>"{searched}"</strong></span><span style={{fontSize:12,background:"#E8F5E9",color:"#2E7D32",padding:"3px 10px",borderRadius:12,fontWeight:500}}>🇷🇴 Romania</span></div><div style={{display:"flex",gap:8}}>{selected.size>0&&<button onClick={handleAddToTracker} style={{padding:"8px 16px",background:added?"#E8F5E9":C.orangeLight,border:`1.5px solid ${added?"#2E7D32":C.orange}`,borderRadius:8,fontSize:13,fontWeight:600,cursor:"pointer",color:added?"#2E7D32":C.orange}}>{added?"Adaugate!":`Adauga in Rank Tracker (${selected.size})`}</button>}<button onClick={()=>exportCSV(sorted,searched)} style={{padding:"8px 16px",background:C.white,border:`1.5px solid ${C.border}`,borderRadius:8,fontSize:13,fontWeight:500,cursor:"pointer",color:C.grayDark}}>Export CSV</button></div></div><div style={{background:C.white,borderRadius:12,border:`1px solid ${C.border}`,overflow:"hidden"}}><table style={{width:"100%",borderCollapse:"collapse"}}><thead><tr style={{background:C.gray,borderBottom:`1px solid ${C.border}`}}><th style={{padding:"12px 16px",width:40}}><input type="checkbox" onChange={toggleAll}/></th><th style={{padding:"12px 16px",textAlign:"left",fontSize:12,fontWeight:600,color:C.grayText,textTransform:"uppercase",letterSpacing:"0.05em"}}># Keyword</th><th onClick={()=>setSortDir(d=>d==="desc"?"asc":"desc")} style={{padding:"12px 16px",textAlign:"left",fontSize:12,fontWeight:600,color:C.orange,textTransform:"uppercase",letterSpacing:"0.05em",cursor:"pointer",width:180}}>Volum {sortDir==="desc"?"▼":"▲"}</th><th style={{padding:"12px 16px",textAlign:"left",fontSize:12,fontWeight:600,color:C.grayText,textTransform:"uppercase",letterSpacing:"0.05em",width:120}}>Trend 12 luni</th></tr></thead><tbody>{sorted.map((row,i)=><tr key={i} style={{borderBottom:`1px solid ${C.grayMid}`,background:selected.has(row.keyword)?C.orangeLight:"transparent"}} onMouseEnter={e=>{if(!selected.has(row.keyword))e.currentTarget.style.background=C.gray;}} onMouseLeave={e=>{e.currentTarget.style.background=selected.has(row.keyword)?C.orangeLight:"transparent";}}><td style={{padding:"13px 16px",textAlign:"center"}}><input type="checkbox" checked={selected.has(row.keyword)} onChange={()=>toggleSelect(row.keyword)}/></td><td style={{padding:"13px 16px"}}><div style={{display:"flex",alignItems:"center",gap:10}}><span style={{fontSize:11,color:C.grayMid,minWidth:20}}>{i+1}</span><span style={{fontWeight:500,fontSize:14,color:C.navy}}>{row.keyword}</span></div></td><td style={{padding:"13px 16px"}}><VolumeBar volume={row.volume} max={maxVol}/></td><td style={{padding:"13px 16px"}}><MiniTrend data={row.trend}/></td></tr>)}</tbody></table></div><p style={{marginTop:14,fontSize:12,color:C.grayText,textAlign:"center"}}>* Date simulate</p></div>}{!results&&!loading&&<EmptyState icon="🔎" title="Introdu un cuvant cheie pentru a incepe" subtitle='Ex: "bec led", "pantofi sport", "telefon samsung"'/>}</div>;}

// ── Blog Topics ───────────────────────────────────────────────────────────────
function BlogTopics(){const[query,setQuery]=useState("");const[results,setResults]=useState(null);const[loading,setLoading]=useState(false);const[searched,setSearched]=useState("");const[filter,setFilter]=useState("all");const handleSearch=()=>{if(!query.trim())return;setLoading(true);setResults(null);setTimeout(()=>{setResults(generateBlogTopics(query));setSearched(query);setFilter("all");setLoading(false);},800);};const filtered=results?results.filter(r=>filter==="all"||r.type===filter):[];const maxVol=results?Math.max(...results.map(r=>r.volume)):1;return <div><h1 style={{fontSize:22,fontWeight:700,marginBottom:4}}>Blog Topic Finder</h1><p style={{color:C.grayText,fontSize:14,marginBottom:24}}>Descopera idei de articole de blog cu volum mare de cautari.</p><div style={{display:"flex",gap:10,marginBottom:28}}><div style={{flex:1,position:"relative"}}><span style={{position:"absolute",left:14,top:"50%",transform:"translateY(-50%)",color:C.grayText}}>✍️</span><input value={query} onChange={e=>setQuery(e.target.value)} onKeyDown={e=>e.key==="Enter"&&handleSearch()} placeholder="Ex: asigurare auto, credit ipotecar..." style={{width:"100%",padding:"12px 14px 12px 42px",border:`1.5px solid ${C.border}`,borderRadius:10,fontSize:15,outline:"none",background:C.white,boxSizing:"border-box"}} onFocus={e=>e.target.style.borderColor=C.orange} onBlur={e=>e.target.style.borderColor=C.border}/></div><button onClick={handleSearch} style={{padding:"12px 28px",background:C.orange,color:C.white,border:"none",borderRadius:10,fontWeight:600,fontSize:15,cursor:"pointer"}}>Cauta</button></div>{loading&&<EmptyState icon="⏳" title="Se genereaza subiectele..."/>}{results&&!loading&&<div><div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:16,flexWrap:"wrap",gap:10}}><span style={{fontSize:14,color:C.grayText}}><strong style={{color:C.navy}}>{filtered.length}</strong> subiecte pentru <strong style={{color:C.orange}}>"{searched}"</strong></span><div style={{display:"flex",gap:6}}>{[["all","Toate"],["direct","Direct legate"],["related","Conexe"]].map(([val,label])=><button key={val} onClick={()=>setFilter(val)} style={{padding:"6px 14px",borderRadius:8,border:"1.5px solid",fontSize:13,cursor:"pointer",fontWeight:500,borderColor:filter===val?C.orange:C.border,background:filter===val?C.orangeLight:C.white,color:filter===val?C.orange:C.grayText}}>{label}</button>)}</div></div><div style={{background:C.white,borderRadius:12,border:`1px solid ${C.border}`,overflow:"hidden"}}><table style={{width:"100%",borderCollapse:"collapse"}}><thead><tr style={{background:C.gray,borderBottom:`1px solid ${C.border}`}}><th style={{padding:"12px 16px",textAlign:"left",fontSize:12,fontWeight:600,color:C.grayText,textTransform:"uppercase",letterSpacing:"0.05em",width:40}}>#</th><th style={{padding:"12px 16px",textAlign:"left",fontSize:12,fontWeight:600,color:C.grayText,textTransform:"uppercase",letterSpacing:"0.05em"}}>Subiect</th><th style={{padding:"12px 16px",textAlign:"left",fontSize:12,fontWeight:600,color:C.grayText,textTransform:"uppercase",letterSpacing:"0.05em",width:120}}>Tip</th><th style={{padding:"12px 16px",textAlign:"left",fontSize:12,fontWeight:600,color:C.grayText,textTransform:"uppercase",letterSpacing:"0.05em",width:160}}>Volum lunar</th></tr></thead><tbody>{filtered.map((row,i)=>{const isDirect=row.type==="direct";return <tr key={i} style={{borderBottom:`1px solid ${C.grayMid}`}} onMouseEnter={e=>e.currentTarget.style.background=C.gray} onMouseLeave={e=>e.currentTarget.style.background="transparent"}><td style={{padding:"13px 16px",fontSize:12,color:C.grayMid}}>{i+1}</td><td style={{padding:"13px 16px",fontWeight:500,fontSize:14,color:C.navy}}>{row.topic}</td><td style={{padding:"13px 16px"}}><span style={{fontSize:11,padding:"3px 10px",borderRadius:12,fontWeight:500,background:isDirect?C.orangeLight:"#EEF1F8",color:isDirect?C.orange:C.navy}}>{isDirect?"Direct":"Conex"}</span></td><td style={{padding:"13px 16px"}}><VolumeBar volume={row.volume} max={maxVol} color={isDirect?C.orange:C.navy}/></td></tr>;})}</tbody></table></div><p style={{marginTop:14,fontSize:12,color:C.grayText,textAlign:"center"}}>* Date simulate</p></div>}{!results&&!loading&&<EmptyState icon="✍️" title="Introdu un subiect pentru a descoperi idei de blog"/>}</div>;}

// ── Rank Tracker ──────────────────────────────────────────────────────────────
function RankTracker({pendingKeywords,onPendingConsumed,onProjectsLoaded,initialProjectId}){
  const[projects,setProjects]=useState(null);const[loading,setLoading]=useState(true);const[activeProject,setActiveProject]=useState(initialProjectId||null);const[showNewProject,setShowNewProject]=useState(false);const[newProjectName,setNewProjectName]=useState("");const[newProjectUrl,setNewProjectUrl]=useState("");const[newKw,setNewKw]=useState("");const[newDevice,setNewDevice]=useState("desktop");const[showAddKw,setShowAddKw]=useState(false);const[sortKw,setSortKw]=useState("pos_asc");const[checking,setChecking]=useState(false);
  useEffect(()=>{loadProjects().then(p=>{const ps=p||[];setProjects(ps);if(initialProjectId)setActiveProject(initialProjectId);else if(ps.length>0)setActiveProject(ps[0].id);setLoading(false);onProjectsLoaded&&onProjectsLoaded(ps);}).catch(()=>{setProjects([]);setLoading(false);});},[]);
  useEffect(()=>{if(initialProjectId)setActiveProject(initialProjectId);},[initialProjectId]);
  useEffect(()=>{if(pendingKeywords&&pendingKeywords.length>0&&projects&&projects.length>0){addKeywordsToProject(activeProject||projects[0].id,pendingKeywords);onPendingConsumed();}},[pendingKeywords,projects]);
  const saveAndUpdate=updated=>{setProjects(updated);saveProjects(updated);onProjectsLoaded&&onProjectsLoaded(updated);};
  const addProject=()=>{if(!newProjectName.trim())return;const proj={id:Date.now(),name:newProjectName.trim(),url:newProjectUrl.trim(),keywords:[]};const updated=[...(projects||[]),proj];saveAndUpdate(updated);setActiveProject(proj.id);setShowNewProject(false);setNewProjectName("");setNewProjectUrl("");};
  const addKeywordsToProject=(projId,keywords)=>{const updated=(projects||[]).map(p=>{if(p.id!==projId)return p;const existing=new Set(p.keywords.map(k=>k.keyword));const newOnes=keywords.filter(kw=>!existing.has(kw)).map(kw=>({id:Date.now()+Math.random(),keyword:kw,position:mockPosition(),url:"",device:newDevice,history:mockHistory()}));return{...p,keywords:[...p.keywords,...newOnes]};});saveAndUpdate(updated);};
  const addSingleKeyword=projId=>{if(!newKw.trim())return;addKeywordsToProject(projId,[newKw.trim()]);setNewKw("");setShowAddKw(false);};
  const removeKeyword=(projId,kwId)=>saveAndUpdate((projects||[]).map(p=>p.id!==projId?p:{...p,keywords:p.keywords.filter(k=>k.id!==kwId)}));
  const updateUrl=(projId,kwId,url)=>saveAndUpdate((projects||[]).map(p=>p.id!==projId?p:{...p,keywords:p.keywords.map(k=>k.id!==kwId?k:{...k,url})}));
  const deleteProject=projId=>{const updated=(projects||[]).filter(p=>p.id!==projId);saveAndUpdate(updated);setActiveProject(updated.length>0?updated[0].id:null);};
  const bulkDevice=val=>saveAndUpdate((projects||[]).map(p=>p.id!==activeProject?p:{...p,keywords:p.keywords.map(k=>({...k,device:val}))}));
  const checkNow=()=>{setChecking(true);setTimeout(()=>{const updated=(projects||[]).map(p=>{if(p.id!==activeProject)return p;const keywords=p.keywords.map(k=>{const newPos=Math.max(1,Math.min(100,k.position+Math.floor(Math.random()*11)-5));const today=new Date().toLocaleDateString("ro-RO",{day:"2-digit",month:"short"});const history=[...(k.history||[]).slice(-29),{date:today,position:newPos}];return{...k,position:newPos,history};});return{...p,keywords};});saveAndUpdate(updated);setChecking(false);},1500);};
  const getSortedKeywords=keywords=>{if(!keywords)return[];const kws=[...keywords];if(sortKw==="volume_desc")return kws.sort((a,b)=>(b.volume||0)-(a.volume||0));if(sortKw==="volume_asc")return kws.sort((a,b)=>(a.volume||0)-(b.volume||0));if(sortKw==="pos_asc")return kws.sort((a,b)=>a.position-b.position);if(sortKw==="pos_desc")return kws.sort((a,b)=>b.position-a.position);if(sortKw==="alpha")return kws.sort((a,b)=>a.keyword.localeCompare(b.keyword));return kws;};
  if(loading)return <EmptyState icon="⏳" title="Se incarca..."/>;
  const proj=projects?.find(p=>p.id===activeProject);
  return(
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:24}}>
        <div><h1 style={{fontSize:22,fontWeight:700,marginBottom:4}}>Rank Tracker</h1><p style={{color:C.grayText,fontSize:14}}>Monitorizeaza pozitiile site-ului tau in Google.</p></div>
        <button onClick={()=>setShowNewProject(true)} style={{padding:"10px 18px",background:C.orange,color:C.white,border:"none",borderRadius:10,fontWeight:600,fontSize:14,cursor:"pointer"}}>+ Proiect nou</button>
      </div>
      {showNewProject&&<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.3)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:100}}><div style={{background:C.white,borderRadius:16,padding:32,width:400,boxShadow:"0 20px 60px rgba(0,0,0,0.15)"}}><h2 style={{fontSize:18,fontWeight:700,marginBottom:20}}>Proiect nou</h2><div style={{marginBottom:14}}><label style={{fontSize:13,fontWeight:500,color:C.grayDark,display:"block",marginBottom:6}}>Nume proiect</label><input value={newProjectName} onChange={e=>setNewProjectName(e.target.value)} placeholder="Ex: Site-ul meu" style={{width:"100%",padding:"10px 12px",border:`1.5px solid ${C.border}`,borderRadius:8,fontSize:14,outline:"none",boxSizing:"border-box"}} onFocus={e=>e.target.style.borderColor=C.orange} onBlur={e=>e.target.style.borderColor=C.border}/></div><div style={{marginBottom:24}}><label style={{fontSize:13,fontWeight:500,color:C.grayDark,display:"block",marginBottom:6}}>URL site</label><input value={newProjectUrl} onChange={e=>setNewProjectUrl(e.target.value)} placeholder="Ex: https://siteulmeu.ro" style={{width:"100%",padding:"10px 12px",border:`1.5px solid ${C.border}`,borderRadius:8,fontSize:14,outline:"none",boxSizing:"border-box"}} onFocus={e=>e.target.style.borderColor=C.orange} onBlur={e=>e.target.style.borderColor=C.border}/></div><div style={{display:"flex",gap:10}}><button onClick={addProject} style={{flex:1,padding:"10px",background:C.orange,color:C.white,border:"none",borderRadius:8,fontWeight:600,cursor:"pointer"}}>Creeaza</button><button onClick={()=>setShowNewProject(false)} style={{flex:1,padding:"10px",background:C.gray,border:`1.5px solid ${C.border}`,borderRadius:8,fontWeight:500,cursor:"pointer",color:C.grayText}}>Anuleaza</button></div></div></div>}
      {projects?.length>0&&<div style={{display:"flex",gap:20}}>
        <div style={{width:200,flexShrink:0}}>
          <div style={{fontSize:11,fontWeight:600,color:C.grayText,textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:8}}>Proiecte</div>
          {projects.map(p=><div key={p.id} onClick={()=>setActiveProject(p.id)} style={{padding:"10px 12px",borderRadius:8,cursor:"pointer",marginBottom:4,background:activeProject===p.id?C.orangeLight:"transparent",border:`1.5px solid ${activeProject===p.id?C.orange:"transparent"}`}}><div style={{fontWeight:600,fontSize:13,color:activeProject===p.id?C.orange:C.navy}}>{p.name}</div><div style={{fontSize:11,color:C.grayText,marginTop:2}}>{p.keywords.length} keywords</div></div>)}
        </div>
        {proj&&<div style={{flex:1,minWidth:0}}>
          <div style={{marginBottom:20}}><div style={{fontWeight:700,fontSize:16,color:C.navy}}>{proj.name}</div>{proj.url&&<div style={{fontSize:12,color:C.orange,marginTop:2}}>{proj.url}</div>}</div>
          {proj.keywords.length===0?<div style={{textAlign:"center",padding:"40px 0",color:C.grayText,background:C.white,borderRadius:12,border:`1px solid ${C.border}`}}><div style={{fontSize:40,marginBottom:12}}>📊</div><p style={{fontSize:14,color:C.grayDark}}>Niciun keyword adaugat inca</p><p style={{fontSize:12,marginTop:4,marginBottom:20}}>Adauga manual sau importa din Keyword Research</p><div style={{display:"flex",gap:10,justifyContent:"center",padding:"0 20px",flexWrap:"wrap"}}><input value={newKw} onChange={e=>setNewKw(e.target.value)} onKeyDown={e=>e.key==="Enter"&&addSingleKeyword(proj.id)} placeholder="Ex: pantofi sport ieftini" style={{padding:"9px 12px",border:`1.5px solid ${C.border}`,borderRadius:8,fontSize:14,outline:"none",width:260}} onFocus={e=>e.target.style.borderColor=C.orange} onBlur={e=>e.target.style.borderColor=C.border}/><button onClick={()=>addSingleKeyword(proj.id)} style={{padding:"9px 18px",background:C.orange,color:C.white,border:"none",borderRadius:8,fontWeight:600,fontSize:14,cursor:"pointer"}}>Adauga</button></div></div>
          :<div>
            <ProjectChart keywords={proj.keywords}/>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16,flexWrap:"wrap",gap:8}}>
              <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap"}}>
                <select value={sortKw} onChange={e=>setSortKw(e.target.value)} style={{padding:"8px 12px",border:`1.5px solid ${C.border}`,borderRadius:8,fontSize:13,outline:"none",background:C.white,cursor:"pointer",color:C.navy}}><option value="pos_asc">Pozitie ▲</option><option value="pos_desc">Pozitie ▼</option><option value="volume_desc">Volum ▼</option><option value="volume_asc">Volum ▲</option><option value="alpha">Alfabetic</option></select>
                <button onClick={checkNow} disabled={checking} style={{padding:"8px 16px",background:checking?C.grayMid:C.orangeLight,color:checking?C.grayText:C.orange,border:`1.5px solid ${checking?C.grayMid:C.orange}`,borderRadius:8,fontSize:13,fontWeight:600,cursor:checking?"not-allowed":"pointer"}}>{checking?"Se verifica...":"Verifica acum"}</button>
                <div style={{display:"flex",gap:4}}>{[["desktop","Desktop"],["mobile","Mobil"]].map(([val,label])=><button key={val} onClick={()=>bulkDevice(val)} style={{padding:"4px 10px",fontSize:12,borderRadius:6,border:`1.5px solid ${C.border}`,cursor:"pointer",fontWeight:500,background:C.gray,color:C.navy}}>{label}</button>)}</div>
              </div>
              <div style={{display:"flex",gap:8}}>
                <button onClick={()=>setShowAddKw(v=>!v)} style={{padding:"8px 16px",background:C.orangeLight,border:`1.5px solid ${C.orange}`,borderRadius:8,fontSize:13,fontWeight:600,cursor:"pointer",color:C.orange}}>+ Adauga keyword</button>
                <button onClick={()=>deleteProject(proj.id)} style={{padding:"8px 12px",background:"#fff5f5",border:"1.5px solid #fca5a5",borderRadius:8,fontSize:13,cursor:"pointer",color:"#ef4444"}}>🗑</button>
              </div>
            </div>
            {showAddKw&&<div style={{background:C.gray,border:`1.5px solid ${C.border}`,borderRadius:10,padding:16,marginBottom:16,display:"flex",gap:10,flexWrap:"wrap",alignItems:"flex-end"}}><div style={{flex:1,minWidth:180}}><label style={{fontSize:12,fontWeight:500,color:C.grayDark,display:"block",marginBottom:4}}>Keyword</label><input value={newKw} onChange={e=>setNewKw(e.target.value)} onKeyDown={e=>e.key==="Enter"&&addSingleKeyword(proj.id)} placeholder="Ex: pantofi sport ieftini" style={{width:"100%",padding:"9px 12px",border:`1.5px solid ${C.border}`,borderRadius:8,fontSize:14,outline:"none",boxSizing:"border-box"}} onFocus={e=>e.target.style.borderColor=C.orange} onBlur={e=>e.target.style.borderColor=C.border}/></div><div><label style={{fontSize:12,fontWeight:500,color:C.grayDark,display:"block",marginBottom:4}}>Dispozitiv</label><select value={newDevice} onChange={e=>setNewDevice(e.target.value)} style={{padding:"9px 12px",border:`1.5px solid ${C.border}`,borderRadius:8,fontSize:14,outline:"none",background:C.white,cursor:"pointer"}}><option value="desktop">Desktop</option><option value="mobile">Mobil</option></select></div><button onClick={()=>addSingleKeyword(proj.id)} style={{padding:"9px 18px",background:C.orange,color:C.white,border:"none",borderRadius:8,fontWeight:600,fontSize:14,cursor:"pointer"}}>Adauga</button></div>}
            <div style={{background:C.white,borderRadius:12,border:`1px solid ${C.border}`,overflow:"auto"}}><table style={{width:"100%",borderCollapse:"collapse",minWidth:600}}><thead><tr style={{background:C.gray,borderBottom:`1px solid ${C.border}`}}><th style={{padding:"12px 16px",textAlign:"left",fontSize:12,fontWeight:600,color:C.grayText,textTransform:"uppercase",letterSpacing:"0.05em"}}>Keyword</th><th style={{padding:"12px 16px",textAlign:"center",fontSize:12,fontWeight:600,color:C.grayText,textTransform:"uppercase",letterSpacing:"0.05em",width:80}}>Pozitie</th><th style={{padding:"12px 16px",textAlign:"left",fontSize:12,fontWeight:600,color:C.grayText,textTransform:"uppercase",letterSpacing:"0.05em"}}>URL</th><th style={{padding:"12px 16px",textAlign:"center",fontSize:12,fontWeight:600,color:C.grayText,textTransform:"uppercase",letterSpacing:"0.05em",width:100}}>Device</th><th style={{padding:"12px 16px",textAlign:"left",fontSize:12,fontWeight:600,color:C.grayText,textTransform:"uppercase",letterSpacing:"0.05em",width:220}}>Evolutie</th><th style={{padding:"12px 16px",width:40}}></th></tr></thead><tbody>{getSortedKeywords(proj.keywords).map(kw=><tr key={kw.id} style={{borderBottom:`1px solid ${C.grayMid}`}} onMouseEnter={e=>e.currentTarget.style.background=C.gray} onMouseLeave={e=>e.currentTarget.style.background="transparent"}><td style={{padding:"13px 16px",fontWeight:500,fontSize:14,color:C.navy}}>{kw.keyword}</td><td style={{padding:"13px 16px",textAlign:"center"}}><PositionBadge pos={kw.position}/></td><td style={{padding:"13px 16px"}}><input value={kw.url} onChange={e=>updateUrl(proj.id,kw.id,e.target.value)} placeholder="https://..." style={{width:"100%",padding:"5px 8px",border:`1.5px solid ${C.border}`,borderRadius:6,fontSize:12,outline:"none",boxSizing:"border-box",color:C.orange}} onFocus={e=>e.target.style.borderColor=C.orange} onBlur={e=>e.target.style.borderColor=C.border}/></td><td style={{padding:"13px 16px",textAlign:"center"}}><select value={kw.device} onChange={e=>saveAndUpdate((projects||[]).map(p=>p.id!==proj.id?p:{...p,keywords:p.keywords.map(k=>k.id!==kw.id?k:{...k,device:e.target.value})}))} style={{padding:"4px 8px",border:`1.5px solid ${C.border}`,borderRadius:6,fontSize:13,outline:"none",background:C.white,cursor:"pointer",color:C.navy}}><option value="desktop">Desktop</option><option value="mobile">Mobil</option></select></td><td style={{padding:"13px 16px"}}><PositionChart history={kw.history}/></td><td style={{padding:"13px 16px"}}><button onClick={()=>removeKeyword(proj.id,kw.id)} style={{background:"none",border:"none",cursor:"pointer",fontSize:18,color:"#fca5a5",padding:4}}>×</button></td></tr>)}</tbody></table></div>
            <p style={{marginTop:14,fontSize:12,color:C.grayText,textAlign:"center"}}>* Pozitii simulate</p>
          </div>}
        </div>}
      </div>}
    </div>
  );
}

// ── Forecasting ───────────────────────────────────────────────────────────────
function Forecasting({projects}){const[selectedProj,setSelectedProj]=useState(null);const[convRate,setConvRate]=useState(2);const[avgOrder,setAvgOrder]=useState(250);const[monthlyCost,setMonthlyCost]=useState(2000);const[horizon,setHorizon]=useState(6);const[scenario,setScenario]=useState("realistic");const[manualKws,setManualKws]=useState([{id:1,keyword:"pantofi sport",volume:22000,currentPos:18,targetPos:5},{id:2,keyword:"pantofi sport ieftini",volume:8500,currentPos:24,targetPos:8},{id:3,keyword:"adidas pantofi",volume:5200,currentPos:35,targetPos:12}]);const[newKw,setNewKw]=useState({keyword:"",volume:"",currentPos:"",targetPos:""});const[source,setSource]=useState("manual");const trackerKws=selectedProj?(selectedProj.keywords||[]).map(k=>({id:k.id,keyword:k.keyword,volume:k.volume||Math.floor(Math.random()*5000+500),currentPos:k.position,targetPos:Math.max(1,Math.floor(k.position*(scenario==="optimistic"?0.4:scenario==="realistic"?0.6:0.8)))})):[];const kws=source==="tracker"?trackerKws:manualKws;const scenMult={optimistic:1.4,realistic:1.0,pessimistic:0.6};const mult=scenMult[scenario];const calcKw=kw=>{const curCTR=getCTR(kw.currentPos);const tgtCTR=getCTR(kw.targetPos);const curTraffic=Math.round(kw.volume*curCTR);const tgtTraffic=Math.round(kw.volume*tgtCTR);return{...kw,curCTR,tgtCTR,curTraffic,tgtTraffic,trafficGain:tgtTraffic-curTraffic};};const calcedKws=kws.map(calcKw);const totalCurTraffic=calcedKws.reduce((s,k)=>s+k.curTraffic,0);const totalTgtTraffic=calcedKws.reduce((s,k)=>s+k.tgtTraffic,0);const totalGain=totalTgtTraffic-totalCurTraffic;const months=Array.from({length:horizon},(_,i)=>{const progress=Math.min(1,((i+1)/horizon)*mult);const traffic=Math.round(totalCurTraffic+totalGain*progress);const conversions=traffic*(convRate/100);const revenue=conversions*avgOrder;return{month:i+1,traffic,conversions:Math.round(conversions),revenue:Math.round(revenue),cost:monthlyCost,roi:monthlyCost>0?Math.round((revenue-monthlyCost)/monthlyCost*100):0};});const finalMonth=months[months.length-1];const totalRevenue=months.reduce((s,m)=>s+m.revenue,0);const totalCost=months.reduce((s,m)=>s+m.cost,0);const overallROI=totalCost>0?Math.round((totalRevenue-totalCost)/totalCost*100):0;const svgW=560,H=130,pad={t:12,r:16,b:28,l:44};const maxTraffic=Math.max(...months.map(m=>m.traffic),1);const maxRev=Math.max(...months.map(m=>m.revenue),1);const invY=(y,H,pad)=>pad.t+(H-pad.t-pad.b)-(y-pad.t);const tPtsInv=months.map((m,i)=>({x:pad.l+(i/Math.max(months.length-1,1))*(svgW-pad.l-pad.r),y:invY(pad.t+(m.traffic/maxTraffic)*(H-pad.t-pad.b),H,pad),traffic:m.traffic,month:m.month}));const rPtsInv=months.map((m,i)=>({x:pad.l+(i/Math.max(months.length-1,1))*(svgW-pad.l-pad.r),y:invY(pad.t+(m.revenue/maxRev)*(H-pad.t-pad.b),H,pad),revenue:m.revenue,month:m.month}));const toLine=pts=>pts.map(p=>`${p.x},${p.y}`).join(" ");const[chartTip,setChartTip]=useState(null);const addManualKw=()=>{if(!newKw.keyword||!newKw.volume)return;setManualKws(prev=>[...prev,{id:Date.now(),keyword:newKw.keyword,volume:parseInt(newKw.volume)||0,currentPos:parseInt(newKw.currentPos)||20,targetPos:parseInt(newKw.targetPos)||5}]);setNewKw({keyword:"",volume:"",currentPos:"",targetPos:""});};const removeKw=id=>setManualKws(prev=>prev.filter(k=>k.id!==id));const updateTargetPos=(id,val)=>setManualKws(prev=>prev.map(k=>k.id===id?{...k,targetPos:Math.max(1,Math.min(100,parseInt(val)||1))}:k));const scenarioColors={optimistic:C.green,realistic:C.navy,pessimistic:C.grayText};const scenarioLabels={optimistic:"Optimist",realistic:"Realist",pessimistic:"Pesimist"};
return(<div><h1 style={{fontSize:22,fontWeight:700,marginBottom:4}}>SEO Forecasting</h1><p style={{color:C.grayText,fontSize:14,marginBottom:24}}>Estimeaza trafic, conversii, venit si ROI pe baza obiectivelor de pozitionare.</p><div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:12,marginBottom:24}}>{[{label:"Rata conversie (%)",val:convRate,set:setConvRate,min:0.1,max:20,step:0.1},{label:"Valoare medie comanda (RON)",val:avgOrder,set:setAvgOrder,min:1,max:10000,step:10},{label:"Cost lunar SEO (RON)",val:monthlyCost,set:setMonthlyCost,min:0,max:50000,step:100},{label:"Orizont (luni)",val:horizon,set:setHorizon,min:1,max:24,step:1}].map((f,i)=><div key={i} style={{background:C.white,border:`1px solid ${C.border}`,borderRadius:10,padding:"12px 14px"}}><label style={{fontSize:11,color:C.grayText,fontWeight:500,display:"block",marginBottom:6}}>{f.label}</label><input type="number" value={f.val} min={f.min} max={f.max} step={f.step} onChange={e=>f.set(parseFloat(e.target.value)||0)} style={{width:"100%",fontSize:16,fontWeight:700,color:C.navy,border:"none",outline:"none",background:"transparent",boxSizing:"border-box"}}/></div>)}</div><div style={{display:"flex",gap:12,marginBottom:20,flexWrap:"wrap",alignItems:"center"}}><div style={{display:"flex",gap:6}}>{["optimistic","realistic","pessimistic"].map(s=><button key={s} onClick={()=>setScenario(s)} style={{padding:"7px 16px",borderRadius:8,border:"1.5px solid",fontSize:13,cursor:"pointer",fontWeight:600,borderColor:scenario===s?scenarioColors[s]:C.border,background:scenario===s?scenarioColors[s]:C.white,color:scenario===s?C.white:C.grayText}}>{scenarioLabels[s]}</button>)}</div><div style={{height:24,width:1,background:C.border}}/><div style={{display:"flex",gap:6}}><button onClick={()=>setSource("manual")} style={{padding:"7px 14px",borderRadius:8,border:"1.5px solid",fontSize:12,cursor:"pointer",fontWeight:500,borderColor:source==="manual"?C.orange:C.border,background:source==="manual"?C.orangeLight:C.white,color:source==="manual"?C.orange:C.grayText}}>✏️ Keywords manuale</button><button onClick={()=>setSource("tracker")} style={{padding:"7px 14px",borderRadius:8,border:"1.5px solid",fontSize:12,cursor:"pointer",fontWeight:500,borderColor:source==="tracker"?C.orange:C.border,background:source==="tracker"?C.orangeLight:C.white,color:source==="tracker"?C.orange:C.grayText}}>📈 Din Rank Tracker</button></div>{source==="tracker"&&<select value={selectedProj?.id||""} onChange={e=>{const p=projects?.find(p=>p.id===parseInt(e.target.value));setSelectedProj(p||null);}} style={{padding:"7px 12px",border:`1.5px solid ${C.border}`,borderRadius:8,fontSize:13,outline:"none",background:C.white,cursor:"pointer",color:C.navy}}><option value="">Selecteaza proiect...</option>{(projects||[]).map(p=><option key={p.id} value={p.id}>{p.name} ({p.keywords.length} kw)</option>)}</select>}</div><div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:12,marginBottom:20}}>{[{label:"Trafic curent / lună",value:fmtN(totalCurTraffic),sub:"vizitatori organici",color:C.grayText,bg:C.gray},{label:`Trafic estimat / lună`,value:fmtN(totalTgtTraffic),sub:`+${fmtN(totalGain)} vizitatori`,color:C.navy,bg:"#EEF1F8"},{label:`Venit estimat (luna ${horizon})`,value:fmtRON(finalMonth.revenue),sub:`${finalMonth.conversions} conversii`,color:C.orange,bg:C.orangeLight},{label:`ROI total (${horizon} luni)`,value:`${overallROI}%`,sub:overallROI>0?"Profitabil ✓":"Sub break-even",color:overallROI>0?C.green:C.red,bg:overallROI>0?C.greenLight:C.redLight}].map((s,i)=><div key={i} style={{background:s.bg,borderRadius:10,padding:"14px 16px"}}><div style={{fontSize:11,color:C.grayText,fontWeight:500,marginBottom:4}}>{s.label}</div><div style={{fontSize:22,fontWeight:700,color:s.color,marginBottom:2}}>{s.value}</div><div style={{fontSize:11,color:C.grayText}}>{s.sub}</div></div>)}</div><div style={{background:C.white,border:`1px solid ${C.border}`,borderRadius:12,padding:20,marginBottom:20}}><div style={{fontWeight:600,fontSize:14,marginBottom:16}}>Proiectie lunara — Trafic &amp; Venit</div><div style={{position:"relative"}}><svg viewBox={`0 0 ${svgW} ${H}`} style={{width:"100%",height:H}} onMouseLeave={()=>setChartTip(null)} onMouseMove={e=>{const r=e.currentTarget.getBoundingClientRect();const mx=(e.clientX-r.left)/r.width*svgW;const near=tPtsInv.reduce((a,b)=>Math.abs(b.x-mx)<Math.abs(a.x-mx)?b:a);setChartTip({x:near.x,m:months[near.month-1]});}}>{[0,0.5,1].map((f,i)=><line key={i} x1={pad.l} y1={pad.t+f*(H-pad.t-pad.b)} x2={svgW-pad.r} y2={pad.t+f*(H-pad.t-pad.b)} stroke={C.grayMid} strokeWidth="1" strokeDasharray="4,3"/>)}{tPtsInv.map((p,i)=><text key={i} x={p.x} y={H-4} fontSize="9" fill={C.grayText} textAnchor="middle">M{p.month}</text>)}<polyline points={toLine(tPtsInv)} fill="none" stroke={C.navy} strokeWidth="2.5" strokeLinejoin="round"/><polyline points={toLine(rPtsInv)} fill="none" stroke={C.orange} strokeWidth="2.5" strokeLinejoin="round" strokeDasharray="6,3"/>{chartTip&&<line x1={chartTip.x} y1={pad.t} x2={chartTip.x} y2={H-pad.b} stroke={C.grayMid} strokeWidth="1" strokeDasharray="3,2"/>}</svg>{chartTip&&<div style={{position:"absolute",top:8,left:chartTip.x/svgW*100>65?"auto":`calc(${chartTip.x/svgW*100}% + 10px)`,right:chartTip.x/svgW*100>65?`calc(${(1-chartTip.x/svgW)*100}% + 10px)`:"auto",background:C.navy,color:C.white,fontSize:11,padding:"8px 12px",borderRadius:8,pointerEvents:"none",lineHeight:1.9}}><div style={{fontWeight:600,marginBottom:2}}>Luna {chartTip.m.month}</div><div><span style={{color:"#aac4ff"}}>Trafic:</span> <strong>{fmtN(chartTip.m.traffic)}</strong></div><div><span style={{color:"#ffb899"}}>Venit:</span> <strong>{fmtRON(chartTip.m.revenue)}</strong></div><div><span style={{color:chartTip.m.roi>=0?"#86efac":"#fca5a5"}}>ROI:</span> <strong>{chartTip.m.roi}%</strong></div></div>}</div><div style={{display:"flex",gap:16,marginTop:8}}><div style={{display:"flex",alignItems:"center",gap:6,fontSize:11,color:C.grayText}}><div style={{width:20,height:2.5,background:C.navy,borderRadius:2}}/>Trafic organic</div><div style={{display:"flex",alignItems:"center",gap:6,fontSize:11,color:C.grayText}}><svg width="20" height="4"><line x1="0" y1="2" x2="20" y2="2" stroke={C.orange} strokeWidth="2.5" strokeDasharray="5,3"/></svg>Venit estimat</div></div></div><div style={{background:C.white,border:`1px solid ${C.border}`,borderRadius:12,overflow:"hidden",marginBottom:20}}><table style={{width:"100%",borderCollapse:"collapse"}}><thead><tr style={{background:C.gray,borderBottom:`1px solid ${C.border}`}}>{["Luna","Trafic","Conversii","Venit (RON)","Cost SEO","ROI"].map(h=><th key={h} style={{padding:"11px 16px",textAlign:"left",fontSize:11,fontWeight:600,color:C.grayText,textTransform:"uppercase",letterSpacing:"0.05em"}}>{h}</th>)}</tr></thead><tbody>{months.map((m,i)=><tr key={i} style={{borderBottom:`1px solid ${C.grayMid}`}} onMouseEnter={e=>e.currentTarget.style.background=C.gray} onMouseLeave={e=>e.currentTarget.style.background="transparent"}><td style={{padding:"11px 16px",fontWeight:600,color:C.navy}}>Luna {m.month}</td><td style={{padding:"11px 16px",color:C.grayDark}}>{fmtN(m.traffic)}</td><td style={{padding:"11px 16px",color:C.grayDark}}>{fmtN(m.conversions)}</td><td style={{padding:"11px 16px",fontWeight:600,color:C.orange}}>{fmtRON(m.revenue)}</td><td style={{padding:"11px 16px",color:C.grayDark}}>{fmtRON(m.cost)}</td><td style={{padding:"11px 16px"}}><span style={{fontWeight:700,fontSize:13,color:m.roi>=0?C.green:C.red,background:m.roi>=0?C.greenLight:C.redLight,padding:"3px 10px",borderRadius:8}}>{m.roi>=0?"+":""}{m.roi}%</span></td></tr>)}</tbody></table></div><div style={{background:C.white,border:`1px solid ${C.border}`,borderRadius:12,overflow:"hidden",marginBottom:12}}><div style={{padding:"14px 16px",borderBottom:`1px solid ${C.border}`,display:"flex",justifyContent:"space-between",alignItems:"center"}}><span style={{fontWeight:600,fontSize:14}}>Keywords în forecast ({calcedKws.length})</span>{source==="manual"&&<span style={{fontSize:12,color:C.grayText}}>Modifica pozitia tinta direct in tabel</span>}</div><table style={{width:"100%",borderCollapse:"collapse",minWidth:600}}><thead><tr style={{background:C.gray,borderBottom:`1px solid ${C.border}`}}>{["Keyword","Volum","Poz. curenta","CTR curent","Poz. tinta","CTR tinta","Trafic câștigat"].map(h=><th key={h} style={{padding:"10px 14px",textAlign:"left",fontSize:11,fontWeight:600,color:C.grayText,textTransform:"uppercase",letterSpacing:"0.04em"}}>{h}</th>)}{source==="manual"&&<th style={{width:36}}/>}</tr></thead><tbody>{calcedKws.map((kw,i)=><tr key={kw.id||i} style={{borderBottom:`1px solid ${C.grayMid}`}} onMouseEnter={e=>e.currentTarget.style.background=C.gray} onMouseLeave={e=>e.currentTarget.style.background="transparent"}><td style={{padding:"11px 14px",fontWeight:500,fontSize:13,color:C.navy}}>{kw.keyword}</td><td style={{padding:"11px 14px",fontSize:13,color:C.grayDark}}>{fmtN(kw.volume)}</td><td style={{padding:"11px 14px"}}><PositionBadge pos={kw.currentPos}/></td><td style={{padding:"11px 14px",fontSize:13,color:C.grayText}}>{(kw.curCTR*100).toFixed(1)}%</td><td style={{padding:"11px 14px"}}>{source==="manual"?<input type="number" min="1" max="100" value={kw.targetPos} onChange={e=>updateTargetPos(kw.id,e.target.value)} style={{width:56,padding:"4px 8px",border:`1.5px solid ${C.border}`,borderRadius:6,fontSize:13,fontWeight:700,color:C.green,outline:"none",textAlign:"center"}} onFocus={e=>e.target.style.borderColor=C.green} onBlur={e=>e.target.style.borderColor=C.border}/>:<PositionBadge pos={kw.targetPos}/>}</td><td style={{padding:"11px 14px",fontSize:13,color:C.green,fontWeight:600}}>{(kw.tgtCTR*100).toFixed(1)}%</td><td style={{padding:"11px 14px"}}><span style={{fontWeight:700,fontSize:13,color:kw.trafficGain>=0?C.green:C.red}}>{kw.trafficGain>=0?"+":""}{fmtN(kw.trafficGain)}</span></td>{source==="manual"&&<td style={{padding:"11px 14px"}}><button onClick={()=>removeKw(kw.id)} style={{background:"none",border:"none",cursor:"pointer",fontSize:16,color:"#fca5a5",padding:4}}>×</button></td>}</tr>)}</tbody></table></div>{source==="manual"&&<div style={{background:C.gray,border:`1.5px solid ${C.border}`,borderRadius:10,padding:14,display:"flex",gap:10,flexWrap:"wrap",alignItems:"flex-end"}}>{[["Keyword","text","keyword"],["Volum lunar","number","volume"],["Poz. curenta","number","currentPos"],["Poz. tinta","number","targetPos"]].map(([label,type,field])=><div key={field} style={{flex:field==="keyword"?2:1,minWidth:100}}><label style={{fontSize:11,fontWeight:500,color:C.grayDark,display:"block",marginBottom:4}}>{label}</label><input type={type} value={newKw[field]} onChange={e=>setNewKw(prev=>({...prev,[field]:e.target.value}))} onKeyDown={e=>e.key==="Enter"&&addManualKw()} placeholder={field==="keyword"?"Ex: pantofi sport":""} style={{width:"100%",padding:"8px 10px",border:`1.5px solid ${C.border}`,borderRadius:7,fontSize:13,outline:"none",boxSizing:"border-box"}} onFocus={e=>e.target.style.borderColor=C.orange} onBlur={e=>e.target.style.borderColor=C.border}/></div>)}<button onClick={addManualKw} style={{padding:"8px 18px",background:C.orange,color:C.white,border:"none",borderRadius:8,fontWeight:600,fontSize:13,cursor:"pointer"}}>+ Adauga</button></div>}<p style={{marginTop:12,fontSize:11,color:C.grayText,textAlign:"center"}}>* Estimari bazate pe CTR mediu per pozitie Google. Date simulate.</p></div>);}

// ── App ───────────────────────────────────────────────────────────────────────
export default function App() {
  const [page, setPage] = useState("projects");
  const [pendingKeywords, setPendingKeywords] = useState([]);
  const [trackerProjects, setTrackerProjects] = useState([]);
  const [loggedUser, setLoggedUser] = useState(null);
  const [selectedProjectId, setSelectedProjectId] = useState(null);

  if (!loggedUser) return <LoginScreen onLogin={setLoggedUser}/>;

  const handleAddToTracker = keywords => { setPendingKeywords(keywords); setPage("rank"); };
  const handleSelectProject = id => { setSelectedProjectId(id); setPage("rank"); };
  const handleNewProjectFromHome = () => { setPage("rank"); };

  const NAV = [
    { id:"projects", icon:"📂", label:"Proiecte" },
    { id:"rank",     icon:"📈", label:"Rank Tracker" },
    { id:"keywords", icon:"🔍", label:"Keyword Research" },
    { id:"blog",     icon:"✍️", label:"Blog Topic Finder" },
    { id:"forecast", icon:"🔮", label:"SEO Forecasting" },
  ];

  const renderPage = () => {
    if (page==="projects") return <ProjectsHome projects={trackerProjects} onSelectProject={handleSelectProject} onNewProject={handleNewProjectFromHome}/>;
    if (page==="keywords") return <KeywordResearch onAddToTracker={handleAddToTracker}/>;
    if (page==="blog")     return <BlogTopics/>;
    if (page==="rank")     return <RankTracker pendingKeywords={pendingKeywords} onPendingConsumed={()=>setPendingKeywords([])} onProjectsLoaded={setTrackerProjects} initialProjectId={selectedProjectId}/>;
    if (page==="forecast") return <Forecasting projects={trackerProjects}/>;
    return null;
  };

  return (
    <div style={{display:"flex",height:"100vh",fontFamily:"Inter,'Segoe UI',sans-serif",background:C.gray,color:C.navy}}>
      <div style={{width:220,background:C.navy,display:"flex",flexDirection:"column",flexShrink:0}}>
        <div style={{padding:"20px 20px 16px",borderBottom:"1px solid rgba(255,255,255,0.08)"}}>
          <Logo variant="dark" width={170}/>
        </div>
        <nav style={{flex:1,padding:"12px 10px",overflowY:"auto"}}>
          <div style={{fontSize:10,fontWeight:600,color:"rgba(255,255,255,0.3)",textTransform:"uppercase",letterSpacing:"0.08em",padding:"4px 12px 8px"}}>Functii</div>
          {NAV.map(item=>(
            <div key={item.id} onClick={()=>setPage(item.id)}
              style={{display:"flex",alignItems:"center",gap:10,padding:"9px 12px",borderRadius:8,cursor:"pointer",marginBottom:2,background:page===item.id?"rgba(255,107,43,0.15)":"transparent",color:page===item.id?C.orange:"rgba(255,255,255,0.85)",fontWeight:600,fontSize:13.5}}>
              <span style={{fontSize:15}}>{item.icon}</span><span>{item.label}</span>
            </div>
          ))}
        </nav>
        <div style={{padding:"12px 16px",borderTop:"1px solid rgba(255,255,255,0.08)"}}>
          <div style={{fontSize:11,color:"rgba(255,255,255,0.5)",marginBottom:8}}>👤 {loggedUser}</div>
          <button onClick={()=>{setLoggedUser(null);setPage("projects");}} style={{width:"100%",padding:"6px",background:"rgba(255,255,255,0.07)",border:"1px solid rgba(255,255,255,0.12)",borderRadius:7,fontSize:11,color:"rgba(255,255,255,0.5)",cursor:"pointer",fontWeight:500}}>Deconectare</button>
          <div style={{fontSize:10,color:"rgba(255,255,255,0.2)",textAlign:"center",marginTop:8}}>v0.4 — date simulate</div>
        </div>
      </div>
      <div style={{flex:1,overflow:"auto",padding:32}}>{renderPage()}</div>
    </div>
  );
}